327→        private TokenCredential? ResolveTokenCredential(
328→            ICredentialFactory? credentialFactory,
329→            ServiceTreeClientOptions options)
330→        {
331→            // When ICredentialFactory is available AND auth mode is DefaultAzureCredential,
332→            // use the factory for cross-tenant support (PME MSI → MSFT tenant token).
333→            if (credentialFactory != null
334→                && options.AuthenticationMode == ServiceTreeAuthenticationMode.DefaultAzureCredential)
335→            {
336→                try
337→                {
338→                    var cred = credentialFactory.CreateTokenCredential(AADTenant.MSFT);
339→                    this.logger.LogInformation(
340→                        "ServiceTreeKustoClient: Using ICredentialFactory for MSFT-tenant credential (type={CredType}).",
341→                        cred.GetType().Name);
342→                    return cred;
343→                }
344→                catch (Exception ex)
345→                {
346→                    this.logger.LogError(
347→                        ex,
348→                        "ServiceTreeKustoClient: ICredentialFactory.CreateTokenCredential failed.");
349→                    throw;
350→                }
351→            }
352→
353→            return this.CreateTokenCredential(options);
354→        }
